import React, { useState } from 'react';
import './App.css'; // General Styles
import './Header.css'; // Header Styles
import './Footer.css'; // Footer Styles
import './NftPreview.css'; // NFT Generator Section Styles
import './Elements.css'; // Button, Inputs, and Other Elements
import logo from './assets/logo.png'; // Adjust the path based on your file structure


function App() {
  const [inputText, setInputText] = useState('');
  const [submitted, setSubmitted] = useState(false);
  const [nftImage, setNftImage] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
    // Simulate image generation after a delay (Replace with actual image generation API)
    setTimeout(() => {
      setNftImage('https://via.placeholder.com/600'); // Placeholder image, replace with generated image URL
    }, 2000);
  };

  return (
    <div className="App">
      {/* Header */}
      <header className="header">
        <img src={logo} alt="Site Logo" className="site-logo" />
        <h1>AI NFT Generator</h1>
        <p>Create and mint your NFT in a minute</p>
      </header>

      {/* Main Content Section */}
      <main>
        <div className="nft-generator-container">
          <form onSubmit={handleSubmit}>
            <input
              type="text"
              className={`form-input ${submitted ? 'submitted' : ''}`}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Describe your image..."
            />
            <button type="submit" className="submit-button">Generate NFT</button>
          </form>

          {nftImage && (
            <div className="nft-image-container">
              <img
                src={nftImage}
                alt="Generated NFT"
                className="nft-image"
              />
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="footer">
        <p>Developed with ❤️ by Ambachain</p>
      </footer>
    </div>
  );
}

export default App;
